func testHabitToManyAddOpSmokingUserProfiles(t *testing.T) {
	var err error

	ctx := context.Background()
	tx := MustTx(boil.BeginTx(ctx, nil))
	defer func() { _ = tx.Rollback() }()

	var a Habit
	var b, c, d, e UserProfile

	seed := randomize.NewSeed()
	if err = randomize.Struct(seed, &a, habitDBTypes, false, strmangle.SetComplement(habitPrimaryKeyColumns, habitColumnsWithoutDefault)...); err != nil {
		t.Fatal(err)
	}
	foreigners := []*UserProfile{&b, &c, &d, &e}
	for _, x := range foreigners {
		if err = randomize.Struct(seed, x, userProfileDBTypes, false, strmangle.SetComplement(userProfilePrimaryKeyColumns, userProfileColumnsWithoutDefault)...); err != nil {
			t.Fatal(err)
		}
	}

	if err := a.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Fatal(err)
	}
	if err = b.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Fatal(err)
	}
	if err = c.Insert(ctx, tx, boil.Infer()); err != nil {
		t.Fatal(err)
	}

	foreignersSplitByInsertion := [][]*UserProfile{
		{&b, &c},
		{&d, &e},
	}

	for i, x := range foreignersSplitByInsertion {
		err = a.AddSmokingUserProfiles(ctx, tx, i != 0, x...)
		if err != nil {
			t.Fatal(err)
		}

		first := x[0]
		second := x[1]

		if !queries.Equal(a.ID, first.SmokingID) {
			t.Error("foreign key was wrong value", a.ID, first.SmokingID)
		}
		if !queries.Equal(a.ID, second.SmokingID) {
			t.Error("foreign key was wrong value", a.ID, second.SmokingID)
		}

		if first.R.Smoking != &a {
			t.Error("relationship was not added properly to the foreign slice")
		}
		if second.R.Smoking != &a {
			t.Error("relationship was not added properly to the foreign slice")
		}

		if a.R.SmokingUserProfiles[i*2] != first {
			t.Error("relationship struct slice not set to correct value")
		}
		if a.R.SmokingUserProfiles[i*2+1] != second {
			t.Error("relationship struct slice not set to correct value")
		}

		count, err := a.SmokingUserProfiles().Count(ctx, tx)
		if err != nil {
			t.Fatal(err)
		}
		if want := int64((i + 1) * 2); count != want {
			t.Error("want", want, "got", count)
		}
	}
}

